        ============================================================ */
     :root {
       --lu-fur:        #211C17;   /* primary fur — head, ears, body */
       --lu-fur-deep:    #38312A;   /* inner-ear / shading tone */
       --lu-contrast:    #F4EEE2;   /* snout patch + shield plate */
       --lu-visor:       #5B5FEF;   /* the "focus" visor — brand accent */
       --lu-visor-glow:  rgba(91, 95, 239, 0.35);
       --lu-nose:        #0F0D0B;   /* nose + lock mark */
       --lu-outline:     rgba(0, 0, 0, 0.06);
     }

     @media (prefers-color-scheme: dark) {
       :root {
         --lu-fur:        #F4EEE2;
         --lu-fur-deep:    #DCD3BF;
         --lu-contrast:    #14131C;
         --lu-visor:       #7B80FF;
         --lu-visor-glow:  rgba(123, 128, 255, 0.45);
         --lu-nose:        #F4EEE2;
         --lu-outline:     rgba(255, 255, 255, 0.08);
       }
     }

     /* Manual overrides — take priority over system preference */
     #lockup-guardian-bear.lu-light {
       --lu-fur: #211C17;
       --lu-fur-deep: #38312A;
       --lu-contrast: #F4EEE2;
       --lu-visor: #5B5FEF;
       --lu-visor-glow: rgba(91, 95, 239, 0.35);
       --lu-nose: #0F0D0B;
       --lu-outline: rgba(0, 0, 0, 0.06);
     }
     #lockup-guardian-bear.lu-dark {
       --lu-fur: #F4EEE2;
       --lu-fur-deep: #DCD3BF;
       --lu-contrast: #14131C;
       --lu-visor: #7B80FF;
       --lu-visor-glow: rgba(123, 128, 255, 0.45);
       --lu-nose: #F4EEE2;
       --lu-outline: rgba(255, 255, 255, 0.08);
     }

     /* Emotion / focus-state visor variants — toggle the "active" class
        from JS to swap expressions, e.g.:
          document.querySelectorAll('.visor-state').forEach(g => g.classList.remove('active'));
          document.getElementById('visor-alert').classList.add('active'); */
     .visor-state { display: none; }
     .visor-state.active { display: inline; }
